fn main() {
    let mut input = String::new();
    use std::io::prelude::*;
    std::io::stdin().read_to_string(&mut input).unwrap();

    let mut it = input.split_whitespace().map(|x| {
        x.parse::<u32>().unwrap()
    });

    let (mut a, b, c) = (
        it.next().unwrap(),
        it.next().unwrap(),
        it.next().unwrap(),
        );

    let mut ans = -1;
    let mut cnt = 0;

    for _ in 0..b + 10 {
        cnt += 1;
        a *= 10;
        let q = a / b;
        if q == c {
            ans = cnt;
            break;
        }
        a -= q * b;
    }

    println!("{}", ans);
}
